   {"word":"休憩","reading":"きゅうけい","romaji":"kyuukei","meaning":"istirahat"},
   {"word":"効率","reading":"こうりつ","romaji":"kouritsu","meaning":"efisiensi"},
   {"word":"締め切り","reading":"しめきり","romaji":"shimekiri","meaning":"tenggat waktu"},
   {"word":"やる気","reading":"やるき","romaji":"yaruki","meaning":"motivasi/semangat"},
   {"word":"計画","reading":"けいかく","romaji":"keikaku","meaning":"rencana"},
   {"word":"あきらめる","reading":"あきらめる","romaji":"akirameru","meaning":"menyerah"},
   {"word":"後悔","reading":"こうかい","romaji":"koukai","meaning":"menyesal"}
