 '[
   {"q":"Berapa jam dalam sehari menurut teks?","options":["12 jam","20 jam","24 jam","36 jam"],"answer":2,"explanation":"「一日は二十四時間しかありません」."},
   {"q":"Apa yang ditulis penulis tiap pagi?","options":["Buku harian","Daftar hal yang akan dikerjakan","Surat","Resep"],"answer":1,"explanation":"「やることをリストに書きます」."},
   {"q":"Hal dikerjakan mulai dari mana?","options":["Dari yang mudah","Dari yang penting","Acak","Dari yang disukai"],"answer":1,"explanation":"「大切なことから順番に」."},
   {"q":"Apa yang membuang-buang waktu?","options":["Tidur","Terlalu sering melihat ponsel","Makan","Olahraga"],"answer":1,"explanation":"「スマホを見すぎると、時間を無駄に」."},
   {"q":"Saat belajar, ponsel ditaruh di mana?","options":["Di saku","Di meja","Di kamar lain","Di tas"],"answer":2,"explanation":"「スマホを別の部屋に置いておきます」."},
