   {"q":"Apa yang dicatat penulis dalam buku keuangan?","options":["Nilai ujian","Untuk apa dan berapa uang dipakai","Jadwal","Belanjaan teman"],"answer":1,"explanation":"「何にいくら使ったか記録します」."},
   {"q":"Agar tidak boros, penulis hanya membeli?","options":["Yang murah","Yang benar-benar perlu","Yang disukai","Yang baru"],"answer":1,"explanation":"「本当に必要な物だけ買います」."},
