   {"q":"Apa yang meningkat akhir-akhir ini?","options":["Pengangguran","Orang yang bekerja dari rumah","Orang pindah ke desa","Jumlah pelancong"],"answer":1,"explanation":"「在宅勤務をする人が増えています」."},
   {"q":"Berkat apa orang bisa bekerja di rumah?","options":["Mobil","Perkembangan internet","Kereta cepat","Robot"],"answer":1,"explanation":"「インターネットの発達で」."},
   {"q":"Kelebihan: tidak perlu waktu apa?","options":["Makan","Komuting (perjalanan kerja)","Tidur","Rapat"],"answer":1,"explanation":"「通勤の時間が要らない」."},
   {"q":"Kekurangan: apa yang jadi sulit?","options":["Makan","Membedakan kerja dan kehidupan pribadi","Tidur","Belanja"],"answer":1,"explanation":"「仕事とプライベートの区別が難しく」."},
   {"q":"Perasaan apa yang bisa muncul saat bekerja sendiri?","options":["Selalu senang","Kesepian","Lapar","Marah"],"answer":1,"explanation":"「孤独を感じることもあります」."},
   {"q":"Agar berhasil kerja dari rumah, apa yang dibutuhkan?","options":["Banyak uang","Manajemen diri","Mobil","Banyak rekan"],"answer":1,"explanation":"「自己管理が必要です」."}
 ]'::jsonb,
